function makeCDF(instanceProbabilities)
{
    var rval = [];
    let totalSum = 0.0;

    for (var x in instanceProbabilities)
    {
        totalSum += instanceProbabilities[x];
        rval.push(totalSum);
    }

    for (var x in rval)
    {
        rval[x] /= totalSum;
    }

    // last value should always be exactly 1
    rval[rval.length-1] = 1.0;

    return rval;
}

// generates a random value, between 0 and valueProbabilities.length-1, where each possible value's chance of
// being generated is listed in the corresponding array entry
function randomWithProbabilities(valueProbabilities)
{
    let randomVal = randomFloat(0.0, 1.0);
    let cdf = makeCDF(valueProbabilities);

    //console.log("" + cdf);
    var x;
    for (x in cdf)
    {
        if (randomVal < cdf[x])
        {
            return x;
        }
    }
    return cdf.length-1;
}

function mapFooter(length)
{
    let rval = "";

    for (var x = 0; x < length; x++)
    {
        rval += "=";
        rval += padStringToLength(""+(x+1), 3, '-');
    }

    return rval;
}

function mapHeader(length)
{
    let rval = "";

    for (var x = 0; x < length; x++)
    {
        rval += "=---";
    }

    return rval;
}

// ------- Grid.js -------
class Grid
{
    constructor(gridX, gridY, gridItemConstructor = function(){return null;})
    {
        checkArgumentsDefinedAndHaveValue(arguments);

        this.contents = new Array()

        this.width = gridX;
        this.height = gridY;
        this.size = gridX * gridY;

        for (let y = 0; y < this.height; y++)
        {
            for (let x = 0; x < this.width; x++)
            {
                this.contents.push(gridItemConstructor(x, y));
            }
        }
    }

    lookup(x,y)
    {
        checkArgumentsDefinedAndHaveValue(arguments);

        if (x < 0 || x >= this.width || y < 0 || y >= this.height)
        {
            return null;
        }

        return this.contents [y * this.width + x];
    }

    // 1D array based lookup
    lookup1D(x)
    {
        checkArgumentsDefinedAndHaveValue(arguments);
        return this.contents[x];
    }

    setValue(x,y,val)
    {
        checkArgumentsDefinedAndHaveValue(arguments);
        this.contents [y * this.width + x] = val;
    }

    setValue1D(x, val)
    {
        this.contents[x] = val;
    }

    getEmptySquare()
    {
        let startIndex = randomInt(0, this.contents.length-1);
        let emptyIndex = null;

        for (let i = 0; i < this.contents.length; i++)
        {
            let lookup = ( startIndex + i ) % this.contents.length;
            if (!this.contents.lookup)
            {
                emptyIndex = i;
                break;
            }
        }

        if (emptyIndex)
        {
            let rx = emptyIndex % this.width;
            let ry = emptyIndex / this.height;

            return {x : rx, y:ry};
        }
        
        return null;
    }

    toStringHyperlink()
    {
        let rval = "";
        for ( let y = 0; y < this.height; y++)
        {
            rval += padStringToLength(""+(y+1), 2) + '|';
            for (let x = 0; x < this.width; x++)
            {
                let lookupVal = this.lookup(x,y).toString();
                if (lookupVal == padStringToLength(' ', lookupVal.length))
                {
                    lookupVal = padStringToLength('.', lookupVal.length);
                }

                let catstr = "<a class=\"map-click\" href=\"javascript:clickGridHandler("+x+","+y+")\">" + lookupVal + "</a>";
                rval += catstr;
            }
            rval += '|';
            rval += '\n';
        }
        return rval;
    }

    toStringTyping()
    {
        let rval = "";
        for ( let y = 0; y < this.height; y++)
        {
            rval += padStringToLength(""+(y+1), 2) + '|';
            for (let x = 0; x < this.width; x++)
            {
                let catstr = this.lookup(x,y).toString();
                rval += catstr;
            }
            rval += '|';
            rval += '\n';
        }
        return rval;
    }

    toString()
    {
        return Grid.TypingFree ? this.toStringHyperlink() : this.toStringTyping();
    }
}

Grid.TypingFree = false;

// ------- GameObject.js -------
class GameObject
{
    constructor(className)
    {
        this.sectorX = 0;
        this.sectorY = 0;
        this.subsectorX = 0;
        this.subsectorY = 0;
        this.entityType = this.constructor.name;

        if (className)
        {
            if (!className.Instances)
            {
                className.Instances = 0;
            }

            className.Instances++;
        }
    }

    isAdjacentTo(obj2)
    {
        let sameSector = (this.sectorX == obj2.sectorX) && (this.sectorY == obj2.sectorY);
        let xSubsectorDiff = Math.abs(this.subsectorX - obj2.subsectorX);
        let ySubsectorDiff = Math.abs(this.subsectorY - obj2.subsectorY);

        console.log("quad x y " + sameSector + " " + xSubsectorDiff + " " + ySubsectorDiff);

        return sameSector && (xSubsectorDiff <= 1) && (ySubsectorDiff <= 1);
    }

    distanceToObject(obj2)
    {
        return this.distanceToSubsectorLoc(obj2.subsectorX, obj2.subsectorY);
    }

    distanceToSubsectorLoc(subsectorX, subsectorY)
    {
        let xdiff = this.subsectorX - subsectorX;
        let ydiff = this.subsectorY - subsectorY;
        return Math.sqrt(xdiff*xdiff + ydiff*ydiff);
    }

    setLocationSector(sectorXY)
    {
        this.sectorX = sectorXY.x;
        this.sectorY = sectorXY.y;
    }

    setLocationSubsector(subsectorXY)
    {
        this.subsectorX = subsectorXY.x;
        this.subsectorY = subsectorXY.y;
    }


    onTorpedoHit(game)
    {
        console.log("Torpedo hit (base class)");
    }

    // randomly generate the number of GameObject instances to put in a new sector
    static randomCountForSector(sectorFreeSpaces, instancesInSector)
    {
        var rval = 0;

        let instanceProbabilities = this.sectorInstanceProbabilities();
        if (instanceProbabilities == null)
        {
            //console.log("Using uniform probability path");
            rval = randomInt(0, this.maxInstancesSector());
        }
        else
        {
            //console.log("Using CDF Probability Path");
            console.assert(instanceProbabilities.length == (1+this.maxInstancesSector()));
            
            rval = randomWithProbabilities(instanceProbabilities);
        }

        rval = Math.min(rval, sectorFreeSpaces);

        // createEntities occurs after we place our minimum number of entities around the map.
        // so if we've already created some entities in this quadrant just deduct them from the ones
        // the rng says we need to create.

        if (!this.Instances)
        {
            this.Instances = 0;
        }

        rval = Math.min(rval, this.maxInstancesGame() - this.Instances);

        console.assert(this.Instances <= this.maxInstancesGame());

        rval = Math.max(rval - instancesInSector, 0);

        return rval;
    }

    subsectorString()
    {
        return "" + (this.subsectorX+1) + ", " + (this.subsectorY+1);
    }

    sectorString()
    {
        return "" + (this.sectorX+1) + ", " + (this.sectorY+1);
    }

    subsectorStringFractional()
    {
        let subsectorXFractional = (this.sectorX+1) + (this.subsectorX / sectorWidthSectors);
        let subsectorYFractional = (this.sectorY+1) + (this.subsectorY / sectorHeightSectors);
        return "("+subsectorXFractional+","+subsectorYFractional+")";
    }

    static minInstancesGame()
    {
        return 0;
    }

    static maxInstancesSector()
    {
        return 8;
    }

    static maxInstancesGame()
    {
        return this.maxInstancesSector() * mapWidthSectors * mapHeightSectors;
    }

    // returns array containing the probability of each instance count appearing in a sector at map generation
    // eg. [.1, .2, .15, .55]
    // means that there's a 10% chance of no instances of the object in a given sector
    // there's a 20% chance of 1 instance
    // a 15% chance of 2 instances
    // a 55% chance of 3 instances
    // The base class GameObject method returns null, if we want to just generate uniform probabilities (default)
    // eg. each number between min and max has an equal likelihood.
    // So in the above example, there'd be a 25% chance of either no instance, 1 instance, 2 instances, or 3 instances
    static sectorInstanceProbabilities()
    {
        return null;
    }
}

// ------- StarBase.js -------
class StarBase extends GameObject
{
    constructor()
    {
        super(StarBase);
        this.shields = StarBase.StartShields;
        this.integrity = StarBase.StartIntegrity;
        this.disabled = false;
        StarBase.starbaseList.push(this);
    }

    isOperational()
    {
        this.ensureDamageFields();
        return !this.disabled && this.integrity > 0;
    }

    ensureDamageFields()
    {
        if (this.shields == null)
        {
            this.shields = StarBase.StartShields;
        }

        if (this.integrity == null)
        {
            this.integrity = StarBase.StartIntegrity;
        }

        if (this.disabled == null)
        {
            this.disabled = false;
        }
    }

    resupplyEnterprise(enterprise)
    {
        let torpedoesRestored = Enterprise.StartTorpedoes - enterprise.torpedoes;
        let energyBefore = enterprise.freeEnergy;

        enterprise.torpedoes = Enterprise.StartTorpedoes;
        enterprise.freeEnergy = Math.max(0, Enterprise.StartEnergy - enterprise.shields);

        gameOutputAppend("\nSTATION: Starbase resupply complete: restored " + torpedoesRestored + " photon torpedo" + (torpedoesRestored == 1 ? "" : "es") + " and " + (enterprise.freeEnergy - energyBefore) + " free energy.");
    }

    destroyByHostiles(game)
    {
        game.currentSector.removeEntity(this);
        StarBase.Instances--;

        let removeSB = this;
        StarBase.starbaseList = StarBase.starbaseList.filter(function(item){return item != removeSB});

        if (game.enterprise.dockStarbase == removeSB)
        {
            game.enterprise.undock(removeSB);
        }

        game.checkStarbaseDock();
        gameOutputAppend("\nWARNING: Starbase in sector " + this.sectorString() + " has been destroyed. Subspace channels fall silent; repair and resupply capacity is reduced.");
    }

    disable(game)
    {
        if (this.disabled)
        {
            return;
        }

        this.disabled = true;

        if (game.enterprise.dockStarbase == this)
        {
            game.enterprise.undock(this);
        }

        game.checkStarbaseDock();
        gameOutputAppend("\nWARNING: Starbase in sector " + this.sectorString() + " is disabled. Emergency lights only; docking support is offline until the sector is secured.");
    }

    takeDamage(energy, game, fromHostile)
    {
        this.ensureDamageFields();
        if (fromHostile)
        {
            game.stationUnderAttack(this);
            gameOutputAppend("\nWARNING: Hostile fire strikes starbase " + this.subsectorString() + " for " + energy + " units; station shields flare across the sector.");
        }
        else
        {
            gameOutputAppend("\nFriendly fire strikes starbase " + this.subsectorString() + " for " + energy + " units.");
        }

        let remainingEnergy = energy;
        if (this.shields > 0)
        {
            let shieldDamage = Math.min(this.shields, remainingEnergy);
            this.shields -= shieldDamage;
            remainingEnergy -= shieldDamage;
        }

        if (remainingEnergy > 0)
        {
            this.integrity -= remainingEnergy;
        }

        if (this.integrity <= 0)
        {
            this.destroyByHostiles(game);
        }
        else
        {
            if (this.shields <= 0 || this.integrity <= StarBase.DisabledIntegrity)
            {
                this.disable(game);
            }

            gameOutputAppend("STATION: Starbase status: shields " + Math.max(0, this.shields) + ", integrity " + Math.max(0, this.integrity) + ".");
        }
    }

    onPhaserHit(energy, game)
    {
        this.takeDamage(energy, game, true);
    }

    onTorpedoHit(game)
    {
        console.log("hit a starbase");

        gameOutputAppend("\nReport from sector " + this.subsectorString());
        if (game.primeUniverse)
        {
            gameOutputAppend("The torpedo strikes the friendly starbase shields! Starfleet records the incident for disciplinary review.");
        }
        else
        {
            gameOutputAppend("The torpedo strikes the Imperial starbase shields! Starfleet orders your second in command to throw you in the agonizer booth, costing you a Stardate.");
            game.advanceStardate(1.0);
        }

        this.takeDamage(StarBase.PlayerTorpedoDamage, game, false);
    }

    toString()
    {
        return ">!<";
    }

    static maxInstancesSector()
    {
        return 1;
    }

    static minInstancesGame()
    {
        return 1;
    }

    static sectorInstanceProbabilities()
    {
        // 5% chance of a starbase in any given quadrant
        return [.95, .05];
    }
}

StarBase.StartShields = 250;
StarBase.StartIntegrity = 300;
StarBase.DisabledIntegrity = 120;
StarBase.PlayerTorpedoDamage = 250;
StarBase.SupportShieldBoost = 50;
StarBase.starbaseList = [];

