// ------- Sector.js -------
class Sector
{
    constructor(widthSubsectorsIn, heightSubsectorsIn, x, y)
    {
        checkArgumentsDefinedAndHaveValue(arguments);
        this.width = widthSubsectorsIn;
        this.height = heightSubsectorsIn;
        this.sectorEntities = new Array();
        this.x = x;
        this.y = y;
    }

    collisionLog(strToPrint)
    {
        if (Sector.CollisionLog)
        {
            console.log(strToPrint);
        }
    }

    populateFromJSData(entitiesSectorJS)
    {
        var x;
        for (x in entitiesSectorJS.sectorEntities)
        {
            let entData = entitiesSectorJS.sectorEntities[x];

            // we construct and insert the enterprise entity elsewhere.
            if (entData.entityType != "Enterprise")
            {
                let ctype = EntityMap.get(entData.entityType);

                let entityObj = new ctype(); 
                Object.assign(entityObj, entData);

                this.sectorEntities.push(entityObj);
            }
        }
    }

    removeEntity(entity)
    {
        let rmindex = this.sectorEntities.indexOf(entity);
        if (rmindex == -1)throw "Entity not found";
        this.sectorEntities.splice( rmindex, 1 );
    }

    entityAtLocation(nextXCoord, nextYCoord)
    {
        nextXCoord = Math.floor(nextXCoord);
        nextYCoord = Math.floor(nextYCoord);
        
        for (var x in this.sectorEntities)
        {
            let objTest = this.sectorEntities[x];

            if ((objTest.subsectorX == nextXCoord) && (objTest.subsectorY == nextYCoord))
            {
                return objTest;
            }
        }

        return null;
    }

    // return a tuple containing
    // the last subsector prior to the intersection
    // and the intersection object (null if none)
    intersectionTest(subsectorX, subsectorY, subsectorXEnd, subsectorYEnd, maxT = 1.0)
    {
        checkArgumentsDefinedAndHaveValue(arguments);

        // polar to euclidean coordinates
        let xVec = subsectorXEnd - subsectorX;
        let yVec = subsectorYEnd - subsectorY;

        // we'll step through the grid in in increments of one cell; -1 if the x / y direction are negative
        let xNextF = xVec > 0.0 ? 1.0 : -1.0;
        let yNextF = yVec > 0.0 ? 1.0 : -1.0;

        // start in the middle of the cell.
        let startCoordX = Math.floor(subsectorX) + .5;
        let startCoordY = Math.floor(subsectorY) + .5;

        let endCoordX = Math.floor(subsectorXEnd) + .5;
        let endCoordY = Math.floor(subsectorYEnd) + .5;

        let currentCoordX = startCoordX;
        let currentCoordY = startCoordY;

        // return values
        let lastCoordX = startCoordX;
        let lastCoordY = startCoordY;
        
        let intersectionObject = null;

        this.collisionLog("start coord " + (startCoordX) + " " + (startCoordY));
        this.collisionLog("end coord " + (endCoordX) + " " + (endCoordY));
        this.collisionLog("vec " + (xVec) + " " + (yVec));

        var nextXInteger = (xVec > 0.0) ? Math.floor(startCoordX) + 1.0 : Math.floor(startCoordX) - 1.0;
        var nextYInteger = (yVec > 0.0) ? Math.floor(startCoordY) + 1.0 : Math.floor(startCoordY) - 1.0;
    
        var steps = 0;

        this.collisionLog("next x y integer coords : " + nextXInteger + " " + nextYInteger);

        // get ray t values for the next cell on each axis
        let tXBound = Math.abs(.50 / xVec);//(nextXInteger - startCoordX) / xVec;
        let tYBound = Math.abs(.50 / yVec);//(nextYInteger - startCoordY) / yVec;

        let txIncrement = Math.abs(1.0 / xVec);
        let tyIncrement = Math.abs(1.0 / yVec);

        // prevent divide by 0
        tXBound = Math.abs(xVec) > .00001 ?  tXBound : Number.MAX_VALUE;
        tYBound = Math.abs(yVec) > .00001 ?  tYBound : Number.MAX_VALUE;

        while (true)
        {
            lastCoordX = Math.floor(currentCoordX);
            lastCoordY = Math.floor(currentCoordY);

            this.collisionLog("t's : " + tXBound + " " + tYBound);

            if (Math.min(tXBound, tYBound) > maxT)
            {
                this.collisionLog("breaking for max t");
                break;
            }

            if (tXBound < tYBound) // hit the x boundary first?
            {
                this.collisionLog("step x " + tXBound);

                currentCoordX = nextXInteger;
                nextXInteger += xNextF;

                tXBound += txIncrement;
            }
            else // hit the y boundary first
            {
                this.collisionLog("step y " + tYBound);

                currentCoordY = nextYInteger;
                nextYInteger += yNextF;

                tYBound += tyIncrement;
            }

            this.collisionLog("stepping to " + currentCoordX + " " + currentCoordY);

            console.assert((currentCoordX != lastCoordX) || (currentCoordY != lastCoordY));

            this.collisionLog("next x y integer coords : " + nextXInteger + " " + nextYInteger);

            if (currentCoordX < 0 || currentCoordY < 0 || currentCoordX >= sectorWidthSubsectors || currentCoordY >= sectorHeightSubsectors)
            {
                this.collisionLog("breaking for out of bounds");
                break;
            }

            // handle intersections
            intersectionObject = this.entityAtLocation(currentCoordX, currentCoordY);

            if (intersectionObject != null)
            {
                this.collisionLog("intersection return");
                break;
            }

            // no escape conditions, so we'll count this as a step
            steps++;
        }

        this.collisionLog("returning with lastcoord " + lastCoordX + " " + lastCoordY);
        this.collisionLog("returning with intersection obj " + intersectionObject);
        this.collisionLog("returning with steps  " + steps);

        return {lastX : lastCoordX, lastY : lastCoordY, intersects : intersectionObject, stepIterations:steps};
    }

    countEntitiesOfType(classtype)
    {
        var rval=0;
        for (var x in this.sectorEntities)
        {
            if (this.sectorEntities[x].constructor == classtype)
            {
                rval++;
            }
        }
        return rval;
    }

    getEntitiesOfType(classtype)
    {
        return this.sectorEntities.filter(function(item){return item.constructor == classtype});
    }

    getEntitiesOfTypes(classTypes)
    {
        return this.sectorEntities.filter(function(item){return classTypes.indexOf(item.constructor) != -1});
    }

    getHostileEntities()
    {
        return this.getEntitiesOfTypes(TrekGame.EnemyTypes);
    }

    getHostileInstallations()
    {
        return this.getEntitiesOfTypes(TrekGame.InstallationTypes);
    }

    getHostileTargets()
    {
        return this.getEntitiesOfTypes(TrekGame.HostileTargetTypes);
    }

    countHostileEntities()
    {
        return this.getHostileEntities().length;
    }

    countHostileTargets()
    {
        return this.getHostileTargets().length;
    }

    isInBounds(x, y)
    {
        return x >= 0 && y >= 0 && x < this.width && y < this.height;
    }

    canEntityMoveTo(entity, x, y)
    {
        x = Math.floor(x);
        y = Math.floor(y);

        if (!this.isInBounds(x, y))
        {
            return false;
        }

        let entityAtDestination = this.entityAtLocation(x, y);
        return entityAtDestination == null || entityAtDestination == entity;
    }

    moveEntity(entity, x, y)
    {
        if (!this.canEntityMoveTo(entity, x, y))
        {
            return false;
        }

        entity.subsectorX = Math.floor(x);
        entity.subsectorY = Math.floor(y);
        return true;
    }

    getAdjacentEntitiesOfType(adjacentToObj, classtype)
    {
        let sblist = this.getEntitiesOfType(classtype);
        return sblist.filter(function(sb){return sb.isAdjacentTo(adjacentToObj)});
    }

    hostileEnemiesMove(game)
    {
        let enemies = this.getHostileEntities().slice();

        for (var x in enemies)
        {
            enemies[x].moveEnemy(game);
        }
    }

    hostileEnemiesFire(target, game)
    {
        let enemyList = this.getHostileEntities();

        if (enemyList.length > 1)
        {
            gameOutputAppend("\nThe hostile vessels fire their weapons.");
        }
        else if (enemyList.length)
        {
            gameOutputAppend("\nThe hostile vessel fires its weapons.");
        }

        for (var x in enemyList)
        {
            let selectedTarget = enemyList[x].selectTarget ? enemyList[x].selectTarget(game) : target;
            enemyList[x].firePhasers(selectedTarget, game);
        }
    }

    klingonsFire(target, game)
    {
        this.hostileEnemiesFire(target, game);
    }

    createEntities(entityTypes)
    {
        var entityIdx;
        for (entityIdx in entityTypes)
        {
            let entityType = entityTypes[entityIdx];

            let numEntities = entityType.randomCountForSector(this.emptySquares(), this.countEntitiesOfType(entityType));

            for (let i =0; i < numEntities; i++ )
            {
                var ent = new entityType();
                this.addEntityInFreeSubsector(ent);
            }
        }
    }

    addEntityInFreeSubsector(entity)
    {
        entity.sectorX = this.x;
        entity.sectorY = this.y;
        entity.setLocationSubsector(this.getEmptySquare());
        this.sectorEntities.push(entity);
    }

    addEntity(entity)
    {
        entity.sectorX = this.x;
        entity.sectorY = this.y;

        this.sectorEntities.push(entity);
    }

    emptySquares()
    {
        return this.width*this.height - this.sectorEntities.length;
    }

    getEmptySquare()
    {
        console.assert(this.width * this.height > this.sectorEntities.length);

        if (this.sectorEntities.length >= this.width*this.height)
        {
            return null;
        }

        let emptyFound = false;

        let testRandom = randomInt(0, (this.width*this.height)-1);

        while (!emptyFound)
        {
            let randomX = testRandom % this.width;
            let randomY = Math.floor(testRandom / this.height);

            var entityIdx;
            emptyFound = true;
            for (entityIdx in this.sectorEntities)
            {
                let entity = this.sectorEntities[entityIdx];
                if (entity.subsectorX == randomX && entity.subsectorY == randomY)
                {
                    emptyFound = false;
                    break;
                }
            }

            if (emptyFound)
            {
                return {x : randomX, y : randomY};
            }

            testRandom++;
        }
    }

    toString()
    {
        let borderStringPost = "   " + mapFooter(sectorWidthSubsectors) + '\n';
        let borderStringPre = "   " + mapHeader(sectorWidthSubsectors); 

        let sectorStringGrid = new Grid(this.width, this.height, function(){return " ".padStart(subsectorDisplayWidthChars, ' ')})

        var gameObjectIndex;
        for (gameObjectIndex in this.sectorEntities)
        {
            let gameObject = this.sectorEntities[gameObjectIndex];
            let objStr = styledMapToken(gameObject.toString(), mapCssClassForEntity(gameObject));
            sectorStringGrid.setValue(gameObject.subsectorX, gameObject.subsectorY, objStr);
        }

        let mapString = sectorStringGrid.toString();

        return "<pre>" + borderStringPre + mapString + borderStringPost + "</pre>";
    }
}

Sector.CollisionLog = false;

// ------- GalaxyMap.js -------
class GalaxyMap extends Grid
{
    constructor(sectorsX, sectorsY, entityTypes)
    {
        checkArgumentsDefinedAndHaveValue(arguments);
        super(sectorsX, sectorsY, function(x, y){return new Sector(sectorWidthSubsectors,sectorHeightSubsectors, x, y)});

        this.createMinimumInstances(entityTypes, sectorsX, sectorsY);

        for (let i = 0; i < sectorsX*sectorsY; i++)
        {
            this.lookup1D(i).createEntities(entityTypes);
        }
    }

    static ConstructFromJSData(jsData)
    {
        let rval = new GalaxyMap(mapWidthSectors, mapHeightSectors, []);

        var x;
        for (x in jsData.contents)
        {
            let entitiesSectorJS = jsData.contents[x];

            rval.contents[x].populateFromJSData(entitiesSectorJS);
        }

        return rval;
    }

    mapString(galaxyMap, EntityType = Klingon, gameobject = null)
    {
        let header = "   ";
        for (let x = 0; x < mapWidthSectors; x++)
        {
            header += padStringToLength((""+(x+1)), 6);
        }

        let border = "------";
        border = border.repeat(mapWidthSectors);
        let rval = header + "\n   " + border + '\n';

        for (let y = 0; y < mapHeightSectors; y++)
        {
            rval += " " + (y+1) + " |";
            for (let x = 0; x < mapWidthSectors; x++)
            {
                let sector = galaxyMap.lookup(x, y);
                
                if (sector)
                {    
                    let k = sector.countEntitiesOfType(EntityType);

                    if (gameobject)
                    {
                        if (gameobject.sectorX == x && gameobject.sectorY == y)
                        {
                            // put an "E" on the map for the enterprise's current location
                            k += 'E';
                        }
                    }

                    rval += " " + padStringToLength(""+k, 3, ' ') + " |";
                }
                else
                {  console.log(" null");
                    rval += " *** |";
                }
             }
             rval += "\n   " + border + "\n";
         }
         return rval;
    }

    createMinimumInstances(entityTypes)
    {
        var x;
        for (x in entityTypes)
        {
            let etype = entityTypes[x];

            let instancesToCreate = etype.minInstancesGame() ;//- etype.Instances;

            console.log("Creating min instances of " + etype.name + " : " + instancesToCreate);
            if (instancesToCreate > 0)
            {
                for (let i = 0; i < instancesToCreate; i++)
                {
                    let inst = new etype();
                    let randomSector = randomInt(0, this.contents.length-1);

                    let instAssigned = false;

                    for (let quad = 0; quad < this.contents.length; quad++)
                    {
                        let sec = this.lookup1D(randomSector);

                        if (sec.emptySquares() && sec.countEntitiesOfType(etype) < etype.maxInstancesSector())
                        {
                            this.lookup1D(randomSector).addEntityInFreeSubsector(inst);
                            instAssigned = true;
                            console.log("inst assigned " + etype.name);
                            break;
                        }

                        randomSector = (randomSector + 1 ) % this.contents.length;
                    }
                    
                    if (!instAssigned)
                    {
                        throw "Not enough space to assign minumum instances of " + etype.name;
                    }
                }
            }
        }
    }
}

// ------- SensorHistory.js -------
class SensorHistory extends Grid
{
    constructor()
    {
        super( mapWidthSectors, mapHeightSectors, function(){return {};} );
    }

    updateSensorHistory(EntityType, galaxyMap, startLocX, startLocY, endLocX, endLocY)
    {
        for (var y = startLocY; y <= endLocY; y++)
        {
            for (var x = startLocX; x <= endLocX; x++)
            {
                let sector = galaxyMap.lookup(x, y);

                if (sector)
                {
                    let ct = sector.countEntitiesOfType(EntityType);
                    this.lookup(x, y)[EntityType] = ct;
                }
            }
        }               
    }

    updateSensorHistoryForEntityTypes(EntityList, galaxyMap, startLocX, startLocY, endLocX, endLocY)
    {
        for (var x in EntityList)
        {
            let EntityType = EntityList[x];
            this.updateSensorHistory(EntityType, galaxyMap, startLocX, startLocY, endLocX, endLocY);
        }
    }

    mapStringForEntityTypes(EntityTypes, gameobject = null)
    {
        let header = "   ";
        for (let x = 0; x < mapWidthSectors; x++)
        {
            header += padStringToLength((""+(x+1)), 6);
        }

        let border = "------";
        border = border.repeat(mapWidthSectors);
        let rval = header + "\n   " + border + '\n';

        for (let y = 0; y < this.height; y++)
        {
            rval += " " + (y+1) + " |";
            for (let x = 0; x < this.width; x++)
            {
                let sectorDict = this.lookup(x, y);
                var k = "";
                var known = false;
                var count = 0;

                for (var entityTypeIndex in EntityTypes)
                {
                    let EntityType = EntityTypes[entityTypeIndex];
                    if (EntityType in sectorDict)
                    {
                        known = true;
                        count += sectorDict[EntityType];
                    }
                }

                k += known ? count : "?";

                if (gameobject)
                {
                    if (gameobject.sectorX == x && gameobject.sectorY == y)
                    {
                        // put an "E" on the map for the enterprise's current location
                        k += 'E';
                    }
                }

                rval += " " + padStringToLength(""+k, 3, ' ') + " |";
             }
             rval += "\n   " + border + "\n";
         }
         return rval;
    }

    mapString(EntityType = Klingon, gameobject = null)
    {
        let header = "   ";
        for (let x = 0; x < mapWidthSectors; x++)
        {
            header += padStringToLength((""+(x+1)), 6);
        }

        let border = "------";
        border = border.repeat(mapWidthSectors);
        let rval = header + "\n   " + border + '\n';

        for (let y = 0; y < this.height; y++)
        {
            rval += " " + (y+1) + " |";
            for (let x = 0; x < this.width; x++)
            {
                let sectorDict = this.lookup(x, y);
                
                if (sectorDict)
                {    
                    var k = "";

                    if (EntityType in sectorDict)
                    {
                        k += sectorDict[EntityType]; // integer count of the entity type
                    }
                    else
                    {
                        k += "?";
                    }

                    if (gameobject)
                    {
                        if (gameobject.sectorX == x && gameobject.sectorY == y)
                        {
                            // put an "E" on the map for the enterprise's current location
                            k += 'E';
                        }
                    }

                    rval += " " + padStringToLength(""+k, 3, ' ') + " |";
                }
                else
                {  console.log(" null");
                    rval += " *** |";
                }
             }
             rval += "\n   " + border + "\n";
         }
         return rval;
     }
}

// ------- Menu.js -------
class MenuOption
{
    constructor(option, separator, description, payload)
    {
        this.option = option.toString();
        this.separator = separator;
        this.description = description;
        this.payload = payload;
        this.enabled = true;
    }

    compare(testString)
    {
        return testString.toLowerCase() == this.option.toLowerCase();
    }

    toString()
    {
        return this.option + this.separator + this.description + '\n';
    }
}

class Menu
{
    constructor()
    {
        this.options = [];
        this.headerString = "ENTER ONE OF THE FOLLOWING:\n";
    }

    getSelectedOption(optionText)
    {
        for (var x in this.options)
        {
            if (this.options[x].compare(optionText) && this.options[x].enabled)
            {
                return this.options[x];
            }
        }
        return null;
    }

    invalidOption()
    {
        gameOutputAppend("Come again, captain?");
        return false;
    }

    chooseOption(optionText)
    {
        var menuopt = this.getSelectedOption(optionText);
        if (menuopt)
        {
            return menuopt.payload();
        }
        return this.invalidOption(optionText);
    }

    toString()
    {
        return Menu.TypingFree ? this.toStringHyperlink() : this.toStringTyping();
    }

    toStringTyping()
    {
        var rstring = this.headerString;

        for (var x in this.options)
        {
            if (this.options[x].enabled)
            {
                rstring += this.options[x];
            }
        }

        return rstring;
    }

    toStringHyperlink()
    {
        var rstring = this.headerString;

        for (var x in this.options)
        {
            if (this.options[x].enabled)
            {
                let sb = "<pre><a href=\"javascript:game.gameInput('" + this.options[x].option + "');\"  style=\"color: rgb(0,255,0)\">";
                let sa = "</a></pre>"
                rstring += sb + this.options[x] + sa;
                //console.log(sb + this.options[x] + sa);
            }
        }

        return rstring;
    }
}

Menu.TypingFree = false;

